mapper.select:
SELECT s.space_id as id, s.space_name, s.space_detail, si.img_url, s.price,
       s.category, s.address, s.max_capacity as maxCapacity
FROM space s
JOIN space_img si ON s.space_id = si.space_id
WHERE si.repimg_yn = 'Y'

    AND s.space_status = #{searchDto.searchSpaceStatus}


    AND s.category = #{searchDto.searchCategory}


    AND s.max_capacity >= #{searchDto.searchMaxCapacity}


    AND s.address LIKE CONCAT('%', #{searchDto.searchAddress}, '%')


    AND (s.space_name LIKE CONCAT('%', #{searchDto.searchQuery}, '%')
    OR s.space_detail LIKE CONCAT('%', #{searchDto.searchQuery}, '%'))

ORDER BY s.space_id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM space s
WHERE 1=1

    AND s.space_status = #{searchDto.searchSpaceStatus}


    AND s.category = #{searchDto.searchCategory}


    AND s.max_capacity >= #{searchDto.searchMaxCapacity}


    AND s.address LIKE CONCAT('%', #{searchDto.searchAddress}, '%')


    AND (s.space_name LIKE CONCAT('%', #{searchDto.searchQuery}, '%')
    OR s.space_detail LIKE CONCAT('%', #{searchDto.searchQuery}, '%'))
